package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;
import java.lang.reflect.InvocationTargetException;
import java.lang.reflect.Method;

public class CSVFormatTest {

    @Test
    public void testWithTrailingDelimiter() throws NoSuchMethodException, InvocationTargetException, IllegalAccessException {
        CSVFormat csvFormat = new CSVFormat(',', '\"', null, null, null, false, true, "\r\n",
                null, null, null, false, false, false, false, false);

        // Using reflection to access the private method
        Method withTrailingDelimiterMethod = CSVFormat.class.getDeclaredMethod("withTrailingDelimiter", boolean.class);
        withTrailingDelimiterMethod.setAccessible(true);
        CSVFormat resultCsvFormat = (CSVFormat) withTrailingDelimiterMethod.invoke(csvFormat, true);

        assertTrue(resultCsvFormat.getTrailingDelimiter());
    }
}
